const input = $input.first().json;

// Campos requeridos
const required = ['nombre', 'email', 'mensaje'];
const missing = required.filter(f => !input[f] || input[f].toString().trim() === '');

if (missing.length > 0) {
  throw new Error(`Campos faltantes: ${missing.join(', ')}`);
}

// Validación de email
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(input.email)) {
  throw new Error(`Email inválido: ${input.email}`);
}

return [{
  json: {
    nombre: input.nombre.trim(),
    email: input.email.toLowerCase().trim(),
    empresa: input.empresa?.trim() || 'No especificada',
    mensaje: input.mensaje.trim(),
    timestamp: new Date().toISOString(),
    execution_id: $execution.id ?? $runIndex + '_' + Date.now()
  }
}];
